"""
mkt-christ commentary — Psalms 41–47
Run: python3 scripts/zc-christ-psalms-41-47.py

Key NT connections:
  Ps41:9   → John 13:18 (direct — Judas betrayal at Last Supper)
  Ps44:22  → Rom 8:36 (direct — sheep for slaughter)
  Ps45:6-7 → Heb 1:8-9 (direct — Your throne O God applied to Son)
  Ps46:4   → John 7:38; Rev 22:1 (direct — river from Christ)
  Ps47:5   → Acts 1:9; Eph 4:8-10 (direct — Ascension)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"41": {"1": "<p><span class=\"level\">theme</span> <em>Blessed is the one who considers the poor! In the day of trouble the LORD delivers him.</em> The beatitude on care for the poor reaches its fulfillment in Christ who pronounces himself the poor to be cared for: <em>I was sick and you visited me... as you did it to one of the least of these my brothers, you did it to me</em> (Matt 25:36-40). The one who delivers the poor is also the one who identifies with them.</p>", "2": "<p><span class=\"level\">theme</span> <em>The LORD protects him and keeps him alive; he is called blessed in the land.</em> Christ is both the Lord who protects and the one who is called blessed: <em>Blessed is the King who comes in the name of the Lord!</em> (Luke 19:38). The one who guards the life of the one who considers the poor is himself the one who laid down his life for the poor in spirit.</p>", "3": "<p><span class=\"level\">shadow</span> <em>The LORD sustains him on his sickbed; in his illness you restore him to full health.</em> Christ the healer restores full health by bearing sickness: <em>He took our illnesses and bore our diseases</em> (Matt 8:17, citing Isa 53:4). The one who restores others to health was himself struck down; the healing flows from his wounds.</p>", "4": "<p><span class=\"level\">shadow</span> <em>As for me, I said, O LORD, be gracious to me; heal me, for I have sinned against you!</em> Christ who knew no sin became sin for us (2 Cor 5:21). Though he had nothing to confess, he descended into the sinner's place — the one who is grace incarnate (John 1:14) receives the petition for healing on behalf of all who pray through him (Rom 8:34).</p>", "5": "<p><span class=\"level\">shadow</span> <em>My enemies say of me in malice, When will he die, and his name perish?</em> Christ's enemies plot his death and the erasure of his name. But the name above every name (Phil 2:9) cannot perish — it is the name at which every knee bows. The malice directed at the righteous sufferer only serves to advance the plan by which his name is exalted forever.</p>", "6": "<p><span class=\"level\">shadow</span> <em>And when one comes to see me, he utters empty words, while his heart gathers iniquity; when he goes out, he tells it abroad.</em> The hypocrisy of those who came to Jesus with empty words while plotting his death: the Pharisees who tested him (Matt 22:15-22), the Sanhedrin members who interrogated him. Their false concern gathers iniquity against the righteous one.</p>", "7": "<p><span class=\"level\">shadow</span> <em>All who hate me whisper together against me; they imagine the worst for me.</em> The Sanhedrin conspiracy: <em>The chief priests and the elders of the people gathered in the palace of the high priest and plotted together</em> (Matt 26:3-4). The whispering conspiracy against Christ fulfills this pattern of enmity toward the righteous sufferer.</p>", "8": "<p><span class=\"level\">shadow</span> <em>They say, A deadly thing is poured out on him; he will not rise again from where he lies.</em> The fatal word — <em>he will not rise again</em> — is the very thing the resurrection overturns. Those who sealed the tomb (Matt 27:66) intended to make the prophecy of enemies permanent. The resurrection of Christ is the definitive refutation of every voice that says he will not rise.</p>", "9": "<p><span class=\"level\">direct</span> <em>Even my close friend in whom I trusted, who ate my bread, has lifted his heel against me.</em> John 13:18 quotes this verse explicitly as Jesus identifies his betrayer at the Last Supper: <em>the Scripture will be fulfilled: He who ate my bread has lifted his heel against me.</em> The betrayal by Judas — who had eaten with Jesus — is the precise fulfillment of Psalm 41:9.</p>", "10": "<p><span class=\"level\">shadow</span> <em>But you, O LORD, be gracious to me, and raise me up, that I may repay them!</em> The prayer for gracious raising — <em>raise me up</em> — is the resurrection prayer. God is gracious to Christ and raises him up, not to repay enemies with vengeance but to intercede for them (Luke 23:34; Rom 8:34).</p>", "11": "<p><span class=\"level\">shadow</span> <em>By this I know that you delight in me: my enemy will not shout in triumph over me.</em> The Father's delight in the Son is declared at the Baptism and Transfiguration: <em>This is my beloved Son, with whom I am well pleased</em> (Matt 3:17; 17:5). The enemy's shout at the cross is temporary; the resurrection silences the triumph and confirms the Father's delight.</p>", "12": "<p><span class=\"level\">shadow</span> <em>But you have upheld me because of my integrity, and set me in your presence forever.</em> God upholds Christ because of his perfect integrity — the sinless Son (Heb 4:15; 1 Pet 2:22) — and sets him in his presence forever: <em>he sat down at the right hand of the Majesty on high</em> (Heb 1:3). The eternal session of Christ fulfills this promise of being set in God's presence.</p>", "13": "<p><span class=\"level\">theme</span> <em>Blessed be the LORD, the God of Israel, from everlasting to everlasting! Amen and Amen.</em> The doxology closing Book I of the Psalter. Christ himself is the eternal Yes and Amen to every promise of God (2 Cor 1:20 — <em>all the promises of God find their Yes in him</em>). The double Amen echoes through the Book of Revelation (Rev 22:20).</p>"}, "42": {"1": "<p><span class=\"level\">shadow</span> <em>As a deer pants for flowing streams, so pants my soul for you, O God.</em> The spiritual thirst of exile finds its answer in Christ's invitation: <em>If anyone thirsts, let him come to me and drink</em> (John 7:37). Christ is the flowing stream — the one who satisfies the panting soul. He is also the deer himself, the righteous sufferer longing for the Father in his desolation.</p>", "2": "<p><span class=\"level\">shadow</span> <em>My soul thirsts for God, for the living God. When shall I come and appear before God?</em> Christ on the cross cries <em>I thirst</em> (John 19:28), inhabiting the exile's longing at its depth. But he is simultaneously the living God (John 20:28 — <em>my Lord and my God</em>) for whom the soul thirsts. He thirsts as the human sufferer and satisfies as the divine source.</p>", "3": "<p><span class=\"level\">shadow</span> <em>My tears have been my food day and night, while they say to me all the day long, Where is your God?</em> The taunt <em>where is your God?</em> is directed at Jesus on the cross: <em>He trusts in God; let God deliver him now, if he desires him</em> (Matt 27:43). The tears of Gethsemane and the cross (Heb 5:7 — loud cries and tears) are the tears that become bread for all who mourn.</p>", "4": "<p><span class=\"level\">shadow</span> <em>These things I remember, as I pour out my soul: how I would go with the throng and lead them in procession to the house of God with glad shouts and songs of praise.</em> Christ's triumphal entry into Jerusalem (Matt 21:1-11) echoes this memory of leading the procession to the house of God with shouts of joy — Hosanna! — before the desolation of the Passion.</p>", "5": "<p><span class=\"level\">shadow</span> <em>Why are you cast down, O my soul, and why are you in turmoil within me? Hope in God; for I shall again praise him, my salvation.</em> First refrain: Gethsemane's anguish — <em>my soul is very sorrowful, even to death</em> (Matt 26:38). Christ commands his own soul to hope in God even in the depths of affliction. The resurrection is the praise that follows — <em>I shall again praise him.</em></p>", "6": "<p><span class=\"level\">shadow</span> <em>My soul is cast down within me; therefore I remember you from the land of Jordan and of Hermon, from Mount Mizar.</em> The geography of exile — Jordan, Hermon — becomes the geography of Christ's ministry and Transfiguration (Hermon is the likely site). He who remembered the Father in the wilderness (Matt 4) and on the mountain (Matt 17) takes up the exile's longing.</p>", "7": "<p><span class=\"level\">shadow</span> <em>Deep calls to deep at the roar of your waterfalls; all your breakers and your waves have gone over me.</em> The cosmic depth of the atonement: the deep of human sin calls to the deep of divine suffering. Paul captures it: God <em>made him to be sin who knew no sin</em> (2 Cor 5:21) — the waters of divine judgment go over the one who descends into the deep for our sake.</p>", "8": "<p><span class=\"level\">revelation of God</span> <em>By day the LORD commands his steadfast love, and at night his song is with me, a prayer to the God of my life.</em> God's chesed commanded by day and song by night reveals the God who is faithful through every darkness. Christ prays through the night (Luke 6:12) and declares the Father's steadfast love — he is the prayer to the God of life, the one who intercedes continuously (Heb 7:25).</p>", "9": "<p><span class=\"level\">shadow</span> <em>I say to God, my rock: Why have you forgotten me? Why do I go mourning because of the oppression of the enemy?</em> The question echoes Ps 22:1 — <em>My God, my God, why have you forsaken me?</em> — the cry Christ makes his own at Calvary (Matt 27:46). God the rock appears to have forgotten the one who calls on him; the resurrection is the answer to this apparent abandonment.</p>", "10": "<p><span class=\"level\">shadow</span> <em>As with a deadly wound in my bones, my adversaries taunt me, while they say to me all the day long, Where is your God?</em> The taunting during the Passion (Matt 27:39-44): <em>he trusts in God; let God deliver him.</em> The deadly wound is literal in Christ's case — the wounds of the cross. The taunt becomes, through resurrection, the occasion for the ultimate answer: <em>God raised him from the dead</em> (Acts 2:24).</p>", "11": "<p><span class=\"level\">shadow</span> <em>Why are you cast down, O my soul, and why are you in turmoil within me? Hope in God; for I shall again praise him, my salvation and my God.</em> The repeated refrain — Gethsemane's hope sustained through suffering. Christ's <em>not my will, but yours, be done</em> (Luke 22:42) is the faith-response embedded in this refrain: hope in God despite soul-anguish. The resurrection makes good the promise.</p>"}, "43": {"1": "<p><span class=\"level\">shadow</span> <em>Vindicate me, O God, and defend my cause against an ungodly people; from the deceitful and unjust man deliver me!</em> Christ's cry for vindication against those who condemned him unjustly. God's vindication comes through resurrection: declared Son of God in power (Rom 1:4). The deceitful witnesses and unjust Pilate are overruled by the verdict of the empty tomb.</p>", "2": "<p><span class=\"level\">shadow</span> <em>For you are the God in whom I take refuge; why have you rejected me? Why do I go about mourning because of the oppression of the enemy?</em> The paradox of the cross — taking refuge in the God who appears to have rejected — is Christ's own experience on Calvary (Ps 22:1; Matt 27:46). The mourning of desolation gives way to the joy of resurrection.</p>", "3": "<p><span class=\"level\">direct</span> <em>Send out your light and your truth; let them lead me; let them bring me to your holy hill and to your dwelling!</em> Christ is both the light sent and the truth sent: <em>I am the way, and the truth, and the life</em> (John 14:6); <em>the true light, which gives light to everyone, was coming into the world</em> (John 1:9). The Father sends his own Son as light and truth to lead his people to the holy mountain of his presence.</p>", "4": "<p><span class=\"level\">shadow</span> <em>Then I will go to the altar of God, to God my exceeding joy, and I will praise you with the lyre, O God, my God.</em> Christ is simultaneously the worshiper and the altar: <em>we have an altar from which those who serve the tent have no right to eat</em> (Heb 13:10). He is the exceeding joy the soul reaches when it comes to God — <em>in your presence there is fullness of joy</em> (Ps 16:11).</p>", "5": "<p><span class=\"level\">shadow</span> <em>Why are you cast down, O my soul, and why are you in turmoil within me? Hope in God; for I shall again praise him, my salvation and my God.</em> The threefold refrain (Ps 42:5, 42:11, 43:5) structures Christ's movement through the Passion: soul cast down in Gethsemane, turbulent at the cross, yet commanding hope in God. The resurrection is the praise that answers all three laments.</p>"}, "44": {"1": "<p><span class=\"level\">theme</span> <em>O God, we have heard with our ears, our fathers have told us, what deeds you performed in their days, in the days of old.</em> The covenant history rehearsed here reaches its climax in Christ. What the fathers told of finds its fulfillment in <em>these last days</em> when God has spoken by his Son (Heb 1:1-2) — the final and definitive act in the drama of redemption.</p>", "2": "<p><span class=\"level\">theme</span> <em>You with your own hand drove out the nations, but them you planted; you afflicted the peoples, but them you set free.</em> The divine warrior's historical acts point to Christ's ultimate victory: <em>he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him</em> (Col 2:15). The pattern of driving out and planting reaches its eschatological fulfillment in the new creation.</p>", "3": "<p><span class=\"level\">theme</span> <em>For not by their own sword did they win the land, nor did their own arm save them, but your right hand and your arm, and the light of your face, for you delighted in them.</em> The principle of divine grace over human achievement is the theological foundation of the gospel: <em>by grace you have been saved through faith. And this is not your own doing; it is the gift of God</em> (Eph 2:8-9). Salvation belongs to the LORD.</p>", "4": "<p><span class=\"level\">shadow</span> <em>You are my King, O God; ordain salvation for Jacob!</em> Christ is the King who ordains salvation — the royal commission to save his people from their sins (Matt 1:21). The kingship of Christ is the ground of salvation; he reigns so that he might redeem (Rev 17:14 — Lord of lords who overcomes).</p>", "5": "<p><span class=\"level\">shadow</span> <em>Through you we push down our foes; through your name we tread down those who rise up against us.</em> The name above every name (Phil 2:9-10) — Christ's name — is the power through which death and sin are trampled. The disciples cast out demons in his name (Luke 10:17); Paul preaches in his name; the Name is the power of the new covenant community.</p>", "6": "<p><span class=\"level\">theme</span> <em>For not in my bow do I trust, nor can my sword save me.</em> Renouncing military power as the means of salvation — fulfilled in Christ who refused the sword: <em>Put your sword back into its place. For all who take the sword will perish by the sword</em> (Matt 26:52). Salvation comes not by the sword of armies but by the weakness of the cross (1 Cor 1:18).</p>", "7": "<p><span class=\"level\">theme</span> <em>But you have saved us from our foes and have put to shame those who hate us.</em> God saves through Christ — the only Savior (Acts 4:12). Those who hated him are put to shame by the resurrection; those who crucified him must acknowledge <em>truly this was the Son of God</em> (Matt 27:54).</p>", "8": "<p><span class=\"level\">theme</span> <em>In God we have boasted continually, and we will give thanks to your name forever.</em> The boasting Paul grounds in Christ: <em>let the one who boasts, boast in the Lord</em> (1 Cor 1:31). The continual thanksgiving finds its fullest voice in the church gathered around Christ — <em>giving thanks always and for everything to God the Father in the name of our Lord Jesus Christ</em> (Eph 5:20).</p>", "9": "<p><span class=\"level\">shadow</span> <em>But you have rejected and disgraced us and have not gone out with our armies.</em> The apparent rejection of God's people — applied by Paul to the present age of Israel's partial hardening (Rom 11:15) — participates in the mystery of the cross where God appeared to abandon his own Son (Matt 27:46). The rejection is real but temporary; restoration follows.</p>", "10": "<p><span class=\"level\">shadow</span> <em>You have made us turn back from the foe, and those who hate us have gotten spoil.</em> Israel's defeat in the lament points to Christ's apparent defeat at the cross — the enemies seemed to get the spoil. But the resurrection reverses it: <em>he led a host of captives</em> (Eph 4:8), taking back what had been seized.</p>", "11": "<p><span class=\"level\">shadow</span> <em>You have made us like sheep for slaughter and have scattered us among the nations.</em> Paul quotes this verse in Romans 8:36 within the passage on Christ's sufferings. The scattered sheep appear in Jesus's Gethsemane prediction: <em>I will strike the shepherd, and the sheep of the flock will be scattered</em> (Matt 26:31, citing Zech 13:7). The imagery connects Passion and apostolic suffering.</p>", "12": "<p><span class=\"level\">shadow</span> <em>You have sold your people for a trifle, demanding no high price for them.</em> The pricing of the righteous one: Jesus is sold for thirty pieces of silver — the price of a slave (Matt 26:15; Zech 11:12-13). God gives his Son for those who are worth far less than the price paid; the trifle for which the people were sold is answered by the infinite price of Christ's blood (1 Pet 1:18-19).</p>", "13": "<p><span class=\"level\">shadow</span> <em>You have made us the taunt of our neighbors, the derision and scorn of those around us.</em> The mockery Christ endures — from Herod's soldiers (Luke 23:11), from the crowd at the cross (Matt 27:39-44) — is the supreme instance of communal derision. The taunt <em>Are you not the Christ? Save yourself!</em> is the voice of the enemy at its worst.</p>", "14": "<p><span class=\"level\">shadow</span> <em>You have made us a byword among the nations, a laughingstock among the peoples.</em> The crucifixion as public spectacle — Roman executions were designed to humiliate. Christ became a <em>byword</em> and <em>laughingstock</em> on the cross: a crucified Messiah was <em>a stumbling block to Jews and folly to Gentiles</em> (1 Cor 1:23). The shame of the cross is the wisdom of God.</p>", "15": "<p><span class=\"level\">shadow</span> <em>All day long my disgrace is before me, and shame has covered my face.</em> Christ endured the cross, despising its shame (Heb 12:2). The disgrace before him all day long is the nakedness and humiliation of crucifixion — the most shameful death in the ancient world. He bore it so that our shame might be covered by his righteousness.</p>", "16": "<p><span class=\"level\">shadow</span> <em>At the sound of the taunting and reviling, at the sight of the enemy and the avenger.</em> The Passion soundscape: taunts from the crowd, reviling from the soldiers, the high priest's mockery. Christ endured all — <em>when he was reviled, he did not revile in return</em> (1 Pet 2:23). The avenger (death) appears to triumph at Golgotha; resurrection overturns the appearance.</p>", "17": "<p><span class=\"level\">shadow</span> <em>All this has come upon us, though we have not forgotten you, and we have not been false to your covenant.</em> The suffering of the innocent is supremely true of Christ. He is the perfectly covenant-faithful one who suffers precisely because of his faithfulness to the Father's plan (Phil 2:8 — <em>obedient to the point of death</em>).</p>", "18": "<p><span class=\"level\">shadow</span> <em>Our heart has not turned back, nor have our steps departed from your way.</em> Christ's unbending faithfulness: <em>he set his face to go to Jerusalem</em> (Luke 9:51) even knowing what awaited him. His heart never turned back — the perfect obedience that becomes righteousness for all who believe (Rom 5:19).</p>", "19": "<p><span class=\"level\">shadow</span> <em>Yet you have broken us in the place of jackals and covered us with the shadow of death.</em> The shadow of death at Calvary — darkness covered the land from noon to three (Matt 27:45). The place of jackals is the desolation of Golgotha. Christ is broken in that place of desolation, covered by the shadow that he came to abolish (2 Tim 1:10).</p>", "20": "<p><span class=\"level\">shadow</span> <em>If we had forgotten the name of our God or spread out our hands to a foreign god,</em> The conditional of innocence: the psalmist asserts they have not abandoned God. Christ never spread his hands to a foreign god — he spread his hands on the cross in absolute fidelity to the Father. His suffering is the purest expression of covenant faithfulness possible.</p>", "21": "<p><span class=\"level\">shadow</span> <em>would not God discover this? For he knows the secrets of the heart.</em> God who knows the secrets of the heart vindicates Christ because he finds there absolute purity: <em>Which of you convicts me of sin?</em> (John 8:46). God declared Jesus righteous by resurrection — the ultimate vindication of a sinless heart.</p>", "22": "<p><span class=\"level\">direct</span> <em>Yet for your sake we are being killed all the day long; we are regarded as sheep to be slaughtered.</em> Romans 8:36 quotes this verse explicitly: <em>As it is written, For your sake we are being killed all the day long; we are regarded as sheep to be slaughtered.</em> Paul frames it with the climactic declaration that nothing can separate us from the love of God in Christ Jesus — the sheep for slaughter are held in the risen Christ's unbreakable grip.</p>", "23": "<p><span class=\"level\">shadow</span> <em>Awake! Why are you sleeping, O Lord? Rouse yourself! Do not reject us forever!</em> The urgent <em>awake</em> — God apparently asleep while his people suffer — is lament at the extremity of affliction. The resurrection is God's awakening to act decisively: he who raised Jesus from the dead (Rom 4:24) vindicates the righteous sufferer and all who are in him.</p>", "24": "<p><span class=\"level\">shadow</span> <em>Why do you hide your face? Why do you forget our affliction and oppression?</em> The hidden face of God — divine abandonment — is Christ's experience on the cross (Ps 22:1; Matt 27:46). The hiddenness is real but not final; the resurrection is the face of God turned again in favor toward the afflicted one and all who are in him.</p>", "25": "<p><span class=\"level\">shadow</span> <em>For our soul is bowed down to the dust; our belly clings to the ground.</em> Humiliation in the dust — the language of death (Gen 3:19). Christ descends to the dust of death (Ps 22:15) and is laid in the earth (John 19:41-42). He who bowed to the dust is raised from it to sit at the right hand of the Majesty on high (Heb 1:3).</p>", "26": "<p><span class=\"level\">shadow</span> <em>Rise up; come to our help! Redeem us for the sake of your steadfast love!</em> The final petition — <em>rise up... redeem us</em> — is answered in the resurrection of Christ. God rises to redeem by raising his Son. The <em>sake of your steadfast love</em> is the motive of the Incarnation and atonement (John 3:16). The rising and the redemption are inseparable.</p>"}, "45": {"1": "<p><span class=\"level\">direct</span> <em>My heart overflows with a pleasing theme; I address my verses to the king; my tongue is like the pen of a ready scribe.</em> The royal wedding song that follows finds its ultimate subject in Christ the King. Hebrews 1:8-9 applies verses 6-7 directly to Christ, transforming this court hymn into a Christological confession. The psalmist's overflow of inspiration is the Spirit's own testimony to the Son.</p>", "2": "<p><span class=\"level\">shadow</span> <em>You are the most handsome of the sons of men; grace is poured upon your lips.</em> Christ is the beautiful one, the one in whom grace is poured — <em>full of grace and truth</em> (John 1:14). The crowds marveled at <em>the gracious words coming from his mouth</em> (Luke 4:22). The beauty of the king is the beauty of holiness and love made visible in the Incarnation.</p>", "3": "<p><span class=\"level\">shadow</span> <em>Gird your sword on your thigh, O mighty one, in your splendor and majesty!</em> The divine warrior imagery reaches Christ: <em>From his mouth comes a sharp sword with which to strike down the nations</em> (Rev 19:15). But his sword is the word — the Word of God who rides forth (Rev 19:13), whose splendor is the glory of the resurrection.</p>", "4": "<p><span class=\"level\">shadow</span> <em>In your majesty ride out victoriously for the cause of truth and meekness and righteousness; let your right hand teach you awesome deeds!</em> Christ rides in the cause of truth, meekness, and righteousness — his own marks: <em>I am the truth</em> (John 14:6); <em>I am gentle and lowly in heart</em> (Matt 11:29); the righteous one (1 John 2:1). The awesome deeds are the cross and resurrection.</p>", "5": "<p><span class=\"level\">shadow</span> <em>Your arrows are sharp in the heart of the king's enemies; the peoples fall under you.</em> The victory of Christ over spiritual enemies: <em>the reason the Son of God appeared was to destroy the works of the devil</em> (1 John 3:8). At the cross the powers are disarmed (Col 2:15); at the parousia the peoples fall before the one who rides on the white horse (Rev 19:11-16).</p>", "6": "<p><span class=\"level\">direct</span> <em>Your throne, O God, is forever and ever. The scepter of your kingdom is a scepter of uprightness.</em> Hebrews 1:8 quotes this verse directly to the Son: <em>But of the Son he says, Your throne, O God, is forever and ever, the scepter of uprightness is the scepter of your kingdom.</em> The Father addresses Christ as God — a direct Christological affirmation of the Son's deity and eternal reign.</p>", "7": "<p><span class=\"level\">direct</span> <em>You have loved righteousness and hated wickedness; therefore God, your God, has anointed you with the oil of gladness beyond your companions.</em> Hebrews 1:9 continues the citation: the anointing of the Son by the Father is his eternal glad anointing as Messiah (Christ = Anointed One). The Spirit descending on Jesus at baptism (Matt 3:16) fulfills the eternal decree of this verse.</p>", "8": "<p><span class=\"level\">shadow</span> <em>Your robes are all fragrant with myrrh and aloes and cassia.</em> The fragrant robes appear in Christ's anointing: Mary's costly nard (John 12:3), the myrrh and aloes at his burial (John 19:39-40). The king's fragrance fills both his life and death — the aroma of Christ (2 Cor 2:15) that spreads from death to life and life to death.</p>", "9": "<p><span class=\"level\">shadow</span> <em>Daughters of kings are among your ladies of honor; at your right hand stands the queen in gold of Ophir.</em> The royal court imagery looks forward to the Bride of Christ: <em>I saw the holy city, new Jerusalem, coming down out of heaven from God, prepared as a bride adorned for her husband</em> (Rev 21:2). The queen at the right hand is the church clothed in the righteousness of Christ (Rev 19:8).</p>", "10": "<p><span class=\"level\">shadow</span> <em>Hear, O daughter, and consider, and incline your ear: forget your people and your father's house,</em> The call to the bride to leave her former family echoes the call of discipleship: <em>Whoever loves father or mother more than me is not worthy of me</em> (Matt 10:37). Christ calls his church to a love that transcends all earthly loyalties in order to be wholly his.</p>", "11": "<p><span class=\"level\">shadow</span> <em>and the king will desire your beauty. Since he is your lord, bow to him.</em> Christ desires the beauty of his church — the beauty he himself imparts: <em>so that he might present the church to himself in splendor, without spot or wrinkle</em> (Eph 5:27). He who is her Lord is also her bridegroom who desires what he has made beautiful through his own blood.</p>", "12": "<p><span class=\"level\">shadow</span> <em>The people of Tyre will seek your favor with gifts, the richest of the people.</em> The nations bringing their glory into the city of God: <em>the kings of the earth will bring their glory into it</em> (Rev 21:24). Christ is the king to whom the nations bring tribute — the universal reach of his reign extending even to Tyre, a symbol of Gentile commercial power.</p>", "13": "<p><span class=\"level\">shadow</span> <em>All glorious is the princess in her chamber, with robes interwoven with gold.</em> The church's inner glory — clothed with Christ's righteousness (Gal 3:27). The fine linen bright and pure given to the bride (Rev 19:8) is the righteous deeds of the saints — the beauty of a people transformed by union with the king.</p>", "14": "<p><span class=\"level\">shadow</span> <em>In many-colored robes she is led to the king, with her virgin companions following behind her.</em> The bridal procession: <em>Let us rejoice and exult and give him the glory, for the marriage of the Lamb has come, and his Bride has made herself ready</em> (Rev 19:7). The many-colored robes are the varied gifts and graces of the Spirit in the gathered church.</p>", "15": "<p><span class=\"level\">shadow</span> <em>With joy and gladness they are led along as they enter the palace of the king.</em> The joy of entry into the King's presence — <em>enter into the joy of your master</em> (Matt 25:23). The wedding feast parable (Matt 22:1-14) and the marriage supper of the Lamb (Rev 19:9 — <em>blessed are those who are invited</em>) give this verse its eschatological fullness.</p>", "16": "<p><span class=\"level\">shadow</span> <em>In place of your fathers shall be your sons; you will make them princes in all the earth.</em> The multiplication of the king's family: Christ makes sons in place of the fathers (Gal 3:29 — heirs of Abraham through faith); the princes in all the earth are the citizens of the kingdom sent as salt and light to every nation (Matt 5:13-14; 28:19).</p>", "17": "<p><span class=\"level\">shadow</span> <em>I will cause your name to be remembered in all generations; therefore nations will praise you forever and ever.</em> The name of Christ remembered in all generations — <em>the name above every name</em> (Phil 2:9). The Great Commission is the mechanism: <em>go and make disciples of all nations... baptizing them in the name</em> (Matt 28:19-20). Every generation and every nation brought into the praise of the King.</p>"}, "46": {"1": "<p><span class=\"level\">revelation of God</span> <em>God is our refuge and strength, a very present help in trouble.</em> The most complete revelation of this divine refuge is the Incarnation: <em>God with us</em> (Matt 1:23 — Immanuel). Christ is the very present help — not distant but tabernacling among us (John 1:14). The church sings this psalm knowing the refuge is a person: <em>in him all things hold together</em> (Col 1:17).</p>", "2": "<p><span class=\"level\">shadow</span> <em>Therefore we will not fear though the earth gives way, though the mountains be moved into the heart of the sea,</em> The earthquake at the crucifixion (Matt 27:51-54) and the cosmic signs of the Passion are the labor pains of the new creation. Those in Christ have no ultimate fear even when the earth gives way, because he has overcome the world (John 16:33).</p>", "3": "<p><span class=\"level\">shadow</span> <em>though its waters roar and foam, though the mountains tremble at its swelling.</em> Chaos imagery reaching to Revelation (Rev 17:15; 21:1 — <em>the sea was no more</em>). Christ commands the sea: <em>he rebuked the wind and the raging waves, and they ceased</em> (Luke 8:24). The trembling mountains give way to the unshakable kingdom (Heb 12:27-28).</p>", "4": "<p><span class=\"level\">direct</span> <em>There is a river whose streams make glad the city of God, the holy habitation of the Most High.</em> John 7:38-39 identifies the river with the Spirit given through Christ: <em>out of his heart will flow rivers of living water.</em> Revelation 22:1-2 depicts the river of the water of life flowing from the throne of God and of the Lamb — Christ is the source of the river that makes glad the city of God.</p>", "5": "<p><span class=\"level\">shadow</span> <em>God is in the midst of her; she shall not be moved; God will help her when morning dawns.</em> <em>God is in the midst</em> — fulfilled when the Word became flesh and dwelt among us (John 1:14). The morning dawning is the resurrection: early on the first day of the week (John 20:1) the dawn brought the help of God in the greatest act of history.</p>", "6": "<p><span class=\"level\">shadow</span> <em>The nations rage, the kingdoms totter; he utters his voice, the earth melts.</em> Acts 4:25-26 quotes Psalm 2:1-2 (the raging nations) in the same idiom. Christ's voice melts opposition: <em>at the name of Jesus every knee should bow</em> (Phil 2:10). The voice that spoke creation into being will speak the new creation at the parousia.</p>", "7": "<p><span class=\"level\">revelation of God</span> <em>The LORD of hosts is with us; the God of Jacob is our fortress.</em> <em>With us</em> — Immanuel (Matt 1:23). The LORD of hosts who commands angelic armies is the one who chose not to call twelve legions of angels (Matt 26:53) in order to save his people. The fortress is not a wall of stone but the risen Christ in whom believers are hidden (Col 3:3).</p>", "8": "<p><span class=\"level\">shadow</span> <em>Come, behold the works of the LORD, how he has brought desolations on the earth.</em> The call to behold God's desolating works — the Passion is the supreme desolation, the place of a skull (Golgotha). The angel's invitation reverses it: <em>Come, see the place where he lay</em> (Matt 28:6) — to behold the work of the LORD at the empty tomb.</p>", "9": "<p><span class=\"level\">shadow</span> <em>He makes wars cease to the end of the earth; he breaks the bow, shatters the spear, and burns the chariots with fire.</em> The eschatological peace of Christ: <em>he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility</em> (Eph 2:14). The broken bow and shattered spear are the powers disarmed at the cross (Col 2:15).</p>", "10": "<p><span class=\"level\">revelation of God</span> <em>Be still, and know that I am God. I will be exalted among the nations, I will be exalted in the earth!</em> <em>I am</em> — the divine name Jesus applies to himself: <em>before Abraham was, I am</em> (John 8:58); <em>I am the resurrection and the life</em> (John 11:25). To be still and know God is to know Christ, through whom God is exalted among all nations as the Great Commission fills the earth.</p>", "11": "<p><span class=\"level\">revelation of God</span> <em>The LORD of hosts is with us; the God of Jacob is our fortress.</em> The refrain repeated — the double assurance of divine presence. Christ's final promise: <em>I am with you always, to the end of the age</em> (Matt 28:20). The LORD of hosts with us is the risen Christ present through his Spirit in the gathered church — the eternal fortress that will not be moved.</p>"}, "47": {"1": "<p><span class=\"level\">shadow</span> <em>Clap your hands, all peoples! Shout to God with loud shouts of joy!</em> The universal acclamation directed at Christ's enthronement: <em>at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord</em> (Phil 2:10-11). The clapping of all peoples is the eschatological praise the Lamb receives (Rev 5:12).</p>", "2": "<p><span class=\"level\">shadow</span> <em>For the LORD, the Most High, is to be feared, a great king over all the earth.</em> Christ is declared the great king over all the earth: <em>All authority in heaven and on earth has been given to me</em> (Matt 28:18). The title Son of the Most High God is used of Jesus by the demon-possessed man (Mark 5:7), who recognizes his absolute sovereignty.</p>", "3": "<p><span class=\"level\">shadow</span> <em>He subdued peoples under us, and nations under our feet.</em> The subjection of all things under Christ's feet: <em>he must reign until he has put all his enemies under his feet</em> (1 Cor 15:25). The church shares in this subduing (Rom 16:20 — <em>the God of peace will soon crush Satan under your feet</em>) as co-heirs with the risen King.</p>", "4": "<p><span class=\"level\">shadow</span> <em>He chose our heritage for us, the pride of Jacob whom he loves.</em> God's election of a people — fulfilled in Christ who is the elect one (Isa 42:1; 1 Pet 2:4) and in whom the elect are chosen: <em>he chose us in him before the foundation of the world</em> (Eph 1:4). The heritage becomes the new creation; the pride of Jacob becomes the Israel of God (Gal 6:16).</p>", "5": "<p><span class=\"level\">direct</span> <em>God has gone up with a shout, the LORD with the sound of a trumpet.</em> The Ascension of Christ: <em>he was lifted up, and a cloud took him out of their sight</em> (Acts 1:9), accompanied by angels. Paul applies the ascending motif in Eph 4:8-10: <em>When he ascended on high he led a host of captives and gave gifts to men.</em> God goes up — the risen Christ ascends to enthronement at the Father's right hand.</p>", "6": "<p><span class=\"level\">shadow</span> <em>Sing praises to God, sing praises! Sing praises to our King, sing praises!</em> The fourfold call to praise is the church's liturgical response to the Ascension. Revelation's throne-room scenes (Rev 4-5) show the living creatures and elders singing praises to the one who sits on the throne and to the Lamb — the singular praise of God and Christ.</p>", "7": "<p><span class=\"level\">shadow</span> <em>For God is the King of all the earth; sing praises with a psalm!</em> Christ as King of all the earth: <em>the kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever</em> (Rev 11:15). The singing with a psalm is what the church does — gathered around Christ as the center of every psalm.</p>", "8": "<p><span class=\"level\">shadow</span> <em>God reigns over the nations; God sits on his holy throne.</em> The enthronement of Christ: <em>when he had made purification for sins, he sat down at the right hand of the Majesty on high</em> (Heb 1:3). His session at the right hand is his reign over the nations — the Psalm's vision of God on his holy throne is fulfilled in the ascended Son who shares the divine throne (Rev 3:21).</p>", "9": "<p><span class=\"level\">shadow</span> <em>The princes of the peoples gather as the people of the God of Abraham. For the shields of the earth belong to God; he is highly exalted!</em> The gathering of the nations under the God of Abraham — fulfilled in the Gentile mission of the church. <em>He is highly exalted</em> — the language of Phil 2:9: <em>God has highly exalted him and bestowed on him the name that is above every name.</em> The shields of the earth belong to the one exalted above all.</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
